def test_is_in_docstring_not_fooled_by_triple_quotes_in_string_literal():
    content = 'x = \'\"\"\"\' \ny = "192.168.1.1"\n'
    ip_pos = content.index('192.168.1.1')
    assert not _is_in_docstring(content, ip_pos), (
        'IP after a string literal containing triple-quotes should not be classified as inside a docstring'
    )

def test_repeated_client_construction_does_not_leak_connections():
    for _ in range(5000):
        c = ServarrClient(ServiceConfig(url='http://localhost', api_key='x'))
        # expected API should allow c.close() or context manager
        c.close()
